import {
  ChangeDetectionStrategy,
  Component,
  ViewEncapsulation,
} from '@angular/core';

/**
 * Toolbar — generic row of small actions for AI message/conversation
 * contexts.
 *
 * Anatomy diff vs rx-ai: the React `Toolbar` wraps `@xyflow/react`
 * `NodeToolbar` and is tied to the workflow-canvas world. AI Elements (the
 * upstream blueprint) actually uses a generic `<div role="toolbar">` outside
 * the canvas, so this Angular port is the generic primitive — three
 * components (Toolbar / ToolbarGroup / ToolbarButton) that compose without
 * @xyflow/angular. Workflow-canvas users compose `<toolbar>` inside an
 * `@xyflow/angular` `<node-toolbar>` wrapper at the app level.
 */
@Component({
  selector: 'toolbar',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<ng-content />`,
  host: {
    role: 'toolbar',
    class:
      'flex items-center gap-1 rounded-sm border bg-background p-1.5',
  },
})
export class Toolbar {}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  ViewEncapsulation,
} from '@angular/core';
import { cn } from '@gremorie/ng-core';

/**
 * ToolbarGroup — visually-grouped subset of toolbar buttons (gap collapsed,
 * shared borders).
 */
@Component({
  selector: 'toolbar-group',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<ng-content />`,
  host: {
    role: 'group',
    '[class]': 'hostClass()',
    '[attr.aria-label]': 'ariaLabel()',
  },
})
export class ToolbarGroup {
  readonly ariaLabel = input<string>();
  readonly orientation = input<'horizontal' | 'vertical'>('horizontal');

  protected readonly hostClass = computed(() =>
    cn(
      'inline-flex items-center',
      this.orientation() === 'horizontal' ? 'flex-row gap-0.5' : 'flex-col gap-0.5',
    ),
  );
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  output,
  ViewEncapsulation,
} from '@angular/core';
import { cn } from '@gremorie/ng-core';

export type ToolbarButtonVariant = 'ghost' | 'outline' | 'default';

/**
 * ToolbarButton — small action button for a toolbar row.
 *
 * Optional `pressed` mirrors a toggle state; emits `(pressedChange)` on
 * click so consumers can drive a controlled toggle group.
 */
@Component({
  selector: 'toolbar-button',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <button
      type="button"
      [class]="buttonClass()"
      [disabled]="disabled()"
      [attr.aria-pressed]="pressed() ? 'true' : null"
      [attr.aria-label]="ariaLabel()"
      (click)="handleClick()"
    >
      <ng-content />
    </button>
  `,
  host: {
    class: 'inline-flex',
  },
})
export class ToolbarButton {
  readonly variant = input<ToolbarButtonVariant>('ghost');
  readonly pressed = input<boolean>(false);
  readonly disabled = input<boolean>(false);
  readonly ariaLabel = input<string>();

  readonly clicked = output<void>();
  readonly pressedChange = output<boolean>();

  protected readonly buttonClass = computed(() => {
    const variantClass: Record<ToolbarButtonVariant, string> = {
      ghost: 'hover:bg-accent hover:text-accent-foreground',
      outline: 'border border-input bg-background hover:bg-accent',
      default:
        'bg-primary text-primary-foreground hover:bg-primary/90',
    };
    return cn(
      'inline-flex size-8 items-center justify-center rounded-sm transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring disabled:pointer-events-none disabled:opacity-50',
      variantClass[this.variant()],
      this.pressed() && 'bg-accent text-accent-foreground',
    );
  });

  protected handleClick(): void {
    this.clicked.emit();
    this.pressedChange.emit(!this.pressed());
  }
}

export { Toolbar } from './toolbar';
export { ToolbarGroup } from './toolbar-group';
export {
  ToolbarButton,
  type ToolbarButtonVariant,
} from './toolbar-button';
